function initDynamicCurrentYear() {  
  const currentYear = new Date().getFullYear();
  const currentYearElements = document.querySelectorAll('[data-current-year]');
  currentYearElements.forEach(currentYearElement => {
    currentYearElement.textContent = currentYear;
  });
}

// Initialize Dynamic Current Year
document.addEventListener('DOMContentLoaded', () => {
  initDynamicCurrentYear();
});

function initScrollAnimations() {
  if (typeof gsap === "undefined" || typeof ScrollTrigger === "undefined") return;

  gsap.registerPlugin(ScrollTrigger);

  const elements = document.querySelectorAll("[data-animate]");

  elements.forEach((el) => {
    const type = el.dataset.animate || "fade";
    const delay = parseFloat(el.dataset.delay) || 0;
    const duration = parseFloat(el.dataset.duration) || 0.8;
    const ease = el.dataset.ease || "expo.out";

    let fromVars = { opacity: 0 };
    let toVars = { opacity: 1 };

    switch (type) {
      case "fade-up":
        fromVars.y = 40;
        break;
      case "fade-down":
        fromVars.y = -40;
        break;
      case "fade-left":
        fromVars.x = 40;
        break;
      case "fade-right":
        fromVars.x = -40;
        break;
      case "zoom":
        fromVars.scale = 0.9;
        break;
    }

    gsap.fromTo(
      el,
      fromVars,
      {
        ...toVars,
        x: 0,
        y: 0,
        scale: 1,
        duration,
        delay,
        ease,
        scrollTrigger: {
          trigger: el,
          start: "top 85%",
          once: true
        }
      }
    );
  });
}

function initDraggableMarquee() {
  const wrappers = document.querySelectorAll("[data-draggable-marquee-init]");

  const getNumberAttr = (el, name, fallback) => {
    const value = parseFloat(el.getAttribute(name));
    return Number.isFinite(value) ? value : fallback;
  };

  wrappers.forEach((wrapper) => {
    if (wrapper.getAttribute("data-draggable-marquee-init") === "initialized") return;

    const collection = wrapper.querySelector("[data-draggable-marquee-collection]");
    const list = wrapper.querySelector("[data-draggable-marquee-list]");
    if (!collection || !list) return;

    const multiplier = getNumberAttr(wrapper, "data-multiplier", 40);
    const sensitivity = getNumberAttr(wrapper, "data-sensitivity", 0.01);

    const wrapperWidth = wrapper.getBoundingClientRect().width;
    const listWidth = list.scrollWidth || list.getBoundingClientRect().width;
    if (!wrapperWidth || !listWidth) return;

    const minRequiredWidth = wrapperWidth + listWidth + 2;
    while (collection.scrollWidth < minRequiredWidth) {
      const listClone = list.cloneNode(true);
      listClone.setAttribute("data-draggable-marquee-clone", "");
      listClone.setAttribute("aria-hidden", "true");
      collection.appendChild(listClone);
    }

    const wrapX = gsap.utils.wrap(-listWidth, 0);

    gsap.set(collection, { x: 0 });

    const marqueeLoop = gsap.to(collection, {
      x: -listWidth,
      duration: 80,
      ease: "none",
      repeat: -1,
      onReverseComplete: () => marqueeLoop.progress(1),
      modifiers: {
        x: (x) => wrapX(parseFloat(x)) + "px"
      }
    });

    const initialDirectionAttr = (wrapper.getAttribute("data-direction") || "left").toLowerCase();
    const baseDirection = initialDirectionAttr === "right" ? -1 : 1;

    const timeScale = { value: 1 };

    timeScale.value = baseDirection;
    wrapper.setAttribute("data-direction", baseDirection < 0 ? "right" : "left");

    if (baseDirection < 0) marqueeLoop.progress(1);

    function applyTimeScale() {
      marqueeLoop.timeScale(timeScale.value);
      wrapper.setAttribute("data-direction", timeScale.value < 0 ? "right" : "left");
    }

    applyTimeScale();

    const marqueeObserver = Observer.create({
      target: wrapper,
      type: "pointer,touch",
      preventDefault: true,
      debounce: false,
      onChangeX: (observerEvent) => {
        let velocityTimeScale = observerEvent.velocityX * -sensitivity;
        velocityTimeScale = gsap.utils.clamp(-multiplier, multiplier, velocityTimeScale);

        gsap.killTweensOf(timeScale);

        const restingDirection = velocityTimeScale < 0 ? -1 : 1;

        gsap.timeline({ onUpdate: applyTimeScale })
          .to(timeScale, { value: velocityTimeScale, duration: 0.1, overwrite: true })
          .to(timeScale, { value: restingDirection, duration: 1.0 });
      }
    });

    ScrollTrigger.create({
      trigger: wrapper,
      start: "top bottom",
      end: "bottom top",
      onEnter: () => {
        marqueeLoop.resume();
        applyTimeScale();
        marqueeObserver.enable();
      },
      onEnterBack: () => {
        marqueeLoop.resume();
        applyTimeScale();
        marqueeObserver.enable();
      },
      onLeave: () => {
        marqueeLoop.pause();
        marqueeObserver.disable();
      },
      onLeaveBack: () => {
        marqueeLoop.pause();
        marqueeObserver.disable();
      }
    });

    wrapper.setAttribute("data-draggable-marquee-init", "initialized");
  });
}

document.addEventListener("DOMContentLoaded", initScrollAnimations);
document.addEventListener("DOMContentLoaded", initDraggableMarquee);

document.addEventListener("DOMContentLoaded", function () {
  document.querySelectorAll("[data-swiper-id]").forEach((section) => {
    const swiperEl = section.querySelector(".swiper");
    const nextEl = section.querySelector(".future-swiper-next");
    const prevEl = section.querySelector(".future-swiper-prev");

    if (!swiperEl || !nextEl || !prevEl) return;

    new Swiper(swiperEl, {
      slidesPerView: "auto",
      slidesPerGroup: 1,
      spaceBetween: 8,
      speed: 700,
      grabCursor: true,
      centeredSlides: false,
      loop: false,
      snapToSlideEdge: true,
      normalizeSlideIndex: true,
      watchOverflow: true,
      navigation: {
        nextEl: nextEl,
        prevEl: prevEl
      }
    });
  });
});

function initHoverCharStagger() {
  const offsetIncrement = 0.015;
  const targets = document.querySelectorAll("[data-hover-chars]");

  targets.forEach((el) => {
    if (el.dataset.splitInitialized === "true") return;
    el.dataset.splitInitialized = "true";

    const text = el.textContent;
    el.innerHTML = "";

    [...text].forEach((char, index) => {
      const span = document.createElement("span");

      span.textContent = char === " " ? "\u00A0" : char;
      span.style.transitionDelay = `${index * offsetIncrement}s`;

      el.appendChild(span);
    });
  });
}

document.addEventListener("DOMContentLoaded", initHoverCharStagger);

function initDynamicTextCursor() {
  const cursor = document.querySelector("[data-cursor]");
  const cursorTextTarget = document.querySelector("[data-cursor-text-target]");

  if (!cursor || !window.matchMedia("(hover: hover) and (pointer: fine)").matches) return;

  let mouseX = 0;
  let mouseY = 0;
  let hasMouseMoved = false;

  const xTo = gsap.quickTo(cursor, "x", { duration: 0.4, ease: "power3.out" });
  const yTo = gsap.quickTo(cursor, "y", { duration: 0.4, ease: "power3.out" });

  function updateCursor() {
    const hoverItem = document.elementFromPoint(mouseX, mouseY)?.closest("[data-cursor-hover]");
    const rect = cursor.getBoundingClientRect();

    const isHovering = !!hoverItem;
    const isEdge = rect.right >= window.innerWidth;

    cursor.setAttribute("data-cursor", isHovering ? (isEdge ? "active-edge" : "active") : "");

    if (hoverItem && cursorTextTarget) {
      const text = hoverItem.getAttribute("data-cursor-text");
      if (text) cursorTextTarget.textContent = text;
    }
  }

  window.addEventListener("mousemove", (event) => {
    mouseX = event.clientX;
    mouseY = event.clientY;
    hasMouseMoved = true;

    xTo(mouseX);
    yTo(mouseY);

    requestAnimationFrame(updateCursor);
  });

  window.addEventListener(
    "scroll",
    () => {
      if (!hasMouseMoved) return;
      requestAnimationFrame(updateCursor);
    },
    { passive: true }
  );
}

document.addEventListener("DOMContentLoaded", initDynamicTextCursor);

if (typeof gsap !== "undefined" && typeof ScrollTrigger !== "undefined" && typeof ScrollToPlugin !== "undefined") {
  gsap.registerPlugin(ScrollTrigger, ScrollToPlugin);
}

function initScrollProgressBar() {
  const progressBar = document.querySelector(".progress-bar");
  const progressBarWrap = document.querySelector(".progress-bar-wrap");

  if (!progressBar || !progressBarWrap || typeof gsap === "undefined" || typeof ScrollTrigger === "undefined") return;

  gsap.to(progressBar, {
    scaleX: 1,
    ease: "none",
    scrollTrigger: {
      trigger: document.body,
      start: "top top",
      end: "bottom bottom",
      scrub: 0.5
    }
  });

  progressBarWrap.addEventListener("click", (event) => {
    const clickX = event.clientX;
    const progress = clickX / progressBarWrap.offsetWidth;
    const scrollPosition = progress * (document.body.scrollHeight - window.innerHeight);

    gsap.to(window, {
      scrollTo: scrollPosition,
      duration: 0.725,
      ease: "power3.out"
    });
  });
}

document.addEventListener("DOMContentLoaded", initScrollProgressBar);

function initScalingHamburgerNavigation() {
  const navStatusEl = document.querySelector("[data-navigation-status]");
  const navigation = document.querySelector(".navigation");

  if (!navStatusEl || !navigation) return;

  const menuItems = Array.from(navigation.querySelectorAll(".hamburger-nav__li"));
  const menuLinks = Array.from(navigation.querySelectorAll(".hamburger-nav__a"));

  let openTween = null;

  function setClosedState() {
    if (typeof gsap === "undefined") return;

    gsap.set(menuItems, {
      opacity: 0,
      y: 32
    });

    gsap.set(menuLinks, {
      opacity: 1
    });
  }

  function animateOpen() {
    if (typeof gsap === "undefined") return;

    if (openTween) openTween.kill();

    openTween = gsap.to(menuItems, {
      opacity: 1,
      y: 0,
      duration: 0.75,
      stagger: 0.095,
      ease: "power3.out",
      delay: 0.28
    });
  }

  function resetLinkOpacity() {
    if (typeof gsap === "undefined") return;

    gsap.to(menuLinks, {
      opacity: 1,
      duration: 0.22,
      ease: "power2.out",
      overwrite: true
    });
  }

  function dimOtherLinks(activeLink) {
    if (typeof gsap === "undefined") return;

    gsap.to(menuLinks, {
      opacity: (i, el) => (el === activeLink ? 1 : 0.3),
      duration: 0.22,
      ease: "power2.out",
      overwrite: true
    });
  }

  function openNavigation() {
    navStatusEl.setAttribute("data-navigation-status", "active");
    animateOpen();
  }

  function closeNavigation() {
    navStatusEl.setAttribute("data-navigation-status", "not-active");
    resetLinkOpacity();
    setClosedState();
  }

  function toggleNavigation() {
    const isActive = navStatusEl.getAttribute("data-navigation-status") === "active";
    if (isActive) closeNavigation();
    else openNavigation();
  }

  document.querySelectorAll('[data-navigation-toggle="toggle"]').forEach((toggleBtn) => {
    toggleBtn.addEventListener("click", toggleNavigation);
  });

  document.querySelectorAll('[data-navigation-toggle="close"]').forEach((closeBtn) => {
    closeBtn.addEventListener("click", closeNavigation);
  });

  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") closeNavigation();
  });

  menuLinks.forEach((link) => {
    link.addEventListener("mouseenter", () => {
      const isActive = navStatusEl.getAttribute("data-navigation-status") === "active";
      if (!isActive) return;
      dimOtherLinks(link);
    });

    link.addEventListener("mouseleave", () => {
      const isActive = navStatusEl.getAttribute("data-navigation-status") === "active";
      if (!isActive) return;
      resetLinkOpacity();
    });

    link.addEventListener("focus", () => {
      const isActive = navStatusEl.getAttribute("data-navigation-status") === "active";
      if (!isActive) return;
      dimOtherLinks(link);
    });

    link.addEventListener("blur", () => {
      const isActive = navStatusEl.getAttribute("data-navigation-status") === "active";
      if (!isActive) return;
      resetLinkOpacity();
    });
  });

  setClosedState();
}

document.addEventListener("DOMContentLoaded", initScalingHamburgerNavigation);

document.addEventListener("DOMContentLoaded", () => {
  if (typeof gsap === "undefined") return;

  document.querySelectorAll(".hero_list_item").forEach((item) => {
    const card = item.querySelector(".hero_folder_card");
    const link = item.querySelector(".hero_list_item_link");
    if (!card || !link) return;

    const front = card.querySelector(".hero_folder_front");
    const thumbs = Array.from(card.querySelectorAll(".hero_folder_thumb"));
    const layers = [front, ...thumbs].filter(Boolean);

    if (!front || !thumbs.length) return;

    thumbs.forEach((thumb, i) => {
      thumb.style.zIndex = 90 - i * 5;
    });
    front.style.zIndex = 100;

    gsap.set(layers, {
      rotationX: 0,
      y: 0,
      transformOrigin: "50% 100%",
      transformStyle: "preserve-3d",
      force3D: true
    });

    const tl = gsap.timeline({ paused: true });

    tl.to(layers, {
      duration: 0.45,
      ease: "power3.out",
      stagger: 0.03,
      rotationX: (i) => Math.min(-45 + i * 10, 0),
      y: (i) => i * -4,
      overwrite: true
    });

    const open = () => tl.play();
    const close = () => tl.reverse();

    link.addEventListener("mouseenter", open);
    link.addEventListener("mouseleave", close);
    link.addEventListener("focus", open);
    link.addEventListener("blur", close);
  });
});

(function () {
  "use strict";

  const destroyers = [];
  let loadRefreshBound = false;
  let isHeroListMode = false;

  function registerDestroyer(fn) {
    if (typeof fn === "function") destroyers.push(fn);
  }

  function destroyAll() {
    while (destroyers.length) {
      const fn = destroyers.pop();
      try {
        fn();
      } catch (e) {
        console.warn("[VDJ] destroy error:", e);
      }
    }
  }

  function safeRefreshScrollTrigger() {
    if (typeof ScrollTrigger !== "undefined") ScrollTrigger.refresh();
  }

  function afterNextPaint(fn) {
    requestAnimationFrame(() => {
      requestAnimationFrame(() => {
        fn();
      });
    });
  }

  function initLenis() {
    if (typeof Lenis === "undefined" || typeof gsap === "undefined" || typeof ScrollTrigger === "undefined") return;

    if (window.lenis && typeof window.lenis.destroy === "function") {
      try {
        window.lenis.destroy();
      } catch (e) {}
    }

    gsap.registerPlugin(ScrollTrigger);

    const lenis = new Lenis({
      lerp: 0.1,
      wheelMultiplier: 0.75,
      touchMultiplier: 0.95,
      smoothWheel: true
    });

    window.lenis = lenis;

    const onScroll = () => ScrollTrigger.update();
    lenis.on("scroll", onScroll);

    const tickerCallback = (time) => {
      lenis.raf(time * 1000);
    };

    gsap.ticker.add(tickerCallback);
    gsap.ticker.lagSmoothing(0);

    registerDestroyer(() => {
      try {
        gsap.ticker.remove(tickerCallback);
      } catch (e) {}

      try {
        lenis.destroy();
      } catch (e) {}

      if (window.lenis === lenis) delete window.lenis;
    });
  }

  function initProjectCardHover(scope = document) {
    if (typeof gsap === "undefined") return;

    const cards = scope.querySelectorAll(".project_card");

    cards.forEach((card) => {
      const details = card.querySelector(".project_details_wrapper");
      if (!details) return;
      if (card.dataset.hoverInitialized === "true") return;

      card.dataset.hoverInitialized = "true";

      gsap.set(details, {
        opacity: 0,
        y: 12
      });

      let tween = null;

      function show() {
        const dragActive = document.getElementById("drag_active");
        if (!dragActive || !dragActive.classList.contains("is-active")) return;

        if (tween) tween.kill();

        tween = gsap.to(details, {
          opacity: 1,
          y: 0,
          duration: 0.35,
          ease: "power2.out"
        });
      }

      function hide() {
        if (tween) tween.kill();

        tween = gsap.to(details, {
          opacity: 0,
          y: 12,
          duration: 0.25,
          ease: "power2.out"
        });
      }

      card.addEventListener("mouseenter", show);
      card.addEventListener("mouseleave", hide);

      registerDestroyer(() => {
        card.removeEventListener("mouseenter", show);
        card.removeEventListener("mouseleave", hide);
      });
    });
  }

  function initTextLoop() {
    if (typeof gsap === "undefined") return;

    const inner = document.querySelector(".text_loop_inner");
    if (!inner) return;

    const label = inner.querySelector("h2");
    const itemsWrap = inner.querySelector(".text_loop_items");
    const listFlex = inner.querySelector(".text_loop_list_flex");

    if (!label || !itemsWrap || !listFlex) return;

    const originalItems = Array.from(listFlex.querySelectorAll(".text_loop_item"));
    if (!originalItems.length) return;

    let loopTween = null;
    let hoveredItem = null;
    let resizeTimer = null;

    function getCenterY(el) {
      const rect = el.getBoundingClientRect();
      return rect.top + rect.height / 2;
    }

    function updateActiveItem() {
      const allItems = Array.from(listFlex.querySelectorAll(".text_loop_item"));
      if (!allItems.length) return;

      if (hoveredItem) {
        allItems.forEach((item) => {
          item.style.opacity = item === hoveredItem ? "1" : "0.25";
        });
        return;
      }

      const labelCenterY = getCenterY(label);
      let closestItem = null;
      let closestDistance = Infinity;

      allItems.forEach((item) => {
        const distance = Math.abs(getCenterY(item) - labelCenterY);
        if (distance < closestDistance) {
          closestDistance = distance;
          closestItem = item;
        }
      });

      allItems.forEach((item) => {
        item.style.opacity = item === closestItem ? "1" : "0.25";
      });
    }

    function getSetHeight(items) {
      const styles = getComputedStyle(listFlex);
      const gap = parseFloat(styles.rowGap || styles.gap) || 0;

      let total = 0;
      items.forEach((item, index) => {
        total += item.offsetHeight;
        if (index < items.length - 1) total += gap;
      });

      return total;
    }

    function pauseLoop() {
      if (loopTween) loopTween.pause();
    }

    function resumeLoop() {
      if (loopTween) loopTween.resume();
    }

    function onMouseOver(e) {
      const item = e.target.closest(".text_loop_item");
      if (!item || !listFlex.contains(item)) return;

      hoveredItem = item;
      pauseLoop();
      updateActiveItem();
    }

    function onMouseOut(e) {
      const item = e.target.closest(".text_loop_item");
      if (!item || !listFlex.contains(item)) return;

      const related = e.relatedTarget;
      if (related && item.contains(related)) return;

      hoveredItem = null;
      resumeLoop();
      updateActiveItem();
    }

    function buildLoop() {
      if (loopTween) {
        loopTween.kill();
        loopTween = null;
      }

      hoveredItem = null;
      gsap.set(listFlex, { y: 0 });

      listFlex.innerHTML = "";
      originalItems.forEach((item) => listFlex.appendChild(item));

      const originalSetHeight = getSetHeight(originalItems);
      const visibleHeight = itemsWrap.offsetHeight;

      if (!originalSetHeight || !visibleHeight) return;

      const minTotalHeight = visibleHeight + originalSetHeight * 2;
      let currentHeight = originalSetHeight;
      let repeatIndex = 0;

      while (currentHeight < minTotalHeight) {
        originalItems.forEach((item) => {
          const clone = item.cloneNode(true);
          clone.setAttribute("aria-hidden", "true");
          listFlex.appendChild(clone);
        });

        repeatIndex++;
        currentHeight = originalSetHeight * (repeatIndex + 1);
      }

      loopTween = gsap.to(listFlex, {
        y: -originalSetHeight,
        duration: 28,
        ease: "none",
        repeat: -1,
        modifiers: {
          y: (value) => {
            const n = parseFloat(value);
            return gsap.utils.wrap(-originalSetHeight, 0, n) + "px";
          }
        },
        onUpdate: updateActiveItem
      });

      updateActiveItem();
    }

    function onResize() {
      clearTimeout(resizeTimer);
      resizeTimer = setTimeout(buildLoop, 150);
    }

    listFlex.addEventListener("mouseover", onMouseOver);
    listFlex.addEventListener("mouseout", onMouseOut);
    window.addEventListener("resize", onResize);

    buildLoop();

    registerDestroyer(() => {
      if (loopTween) loopTween.kill();
      clearTimeout(resizeTimer);
      listFlex.removeEventListener("mouseover", onMouseOver);
      listFlex.removeEventListener("mouseout", onMouseOut);
      window.removeEventListener("resize", onResize);
    });
  }

  function initFooterParallax() {
    if (typeof gsap === "undefined" || typeof ScrollTrigger === "undefined") return;

    gsap.registerPlugin(ScrollTrigger);

    const timelines = [];

    document.querySelectorAll("[data-footer-parallax]").forEach((el) => {
      const inner = el.querySelector("[data-footer-parallax-inner]");
      const dark = el.querySelector("[data-footer-parallax-dark]");

      if (!inner && !dark) return;

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: el,
          start: "top bottom",
          end: "top top",
          scrub: true,
          invalidateOnRefresh: true
        }
      });

      if (inner) {
        tl.fromTo(inner, { yPercent: -25 }, { yPercent: 0, ease: "none" }, 0);
      }

      if (dark) {
        tl.fromTo(dark, { opacity: 0.5 }, { opacity: 1, ease: "none" }, 0);
      }

      timelines.push(tl);
    });

    registerDestroyer(() => {
      timelines.forEach((tl) => {
        try {
          if (tl.scrollTrigger) tl.scrollTrigger.kill();
          tl.kill();
        } catch (e) {}
      });
    });
  }

  const splitConfig = {
    lines: { duration: 0.8, stagger: 0.08 },
    words: { duration: 0.6, stagger: 0.06 },
    chars: { duration: 0.4, stagger: 0.01 }
  };

  function initMaskTextScrollReveal() {
    if (typeof gsap === "undefined" || typeof SplitText === "undefined" || typeof ScrollTrigger === "undefined") return;

    gsap.registerPlugin(ScrollTrigger, SplitText);

    const splits = [];
    const triggers = [];

    document.querySelectorAll('[data-split="heading"]').forEach((heading) => {
      const type = ["lines", "words", "chars"].includes(heading.dataset.splitReveal) ? heading.dataset.splitReveal : "lines";
      const isImmediate = heading.dataset.splitImmediate === "true";

      const typesToSplit = type === "lines" ? ["lines"] : type === "words" ? ["lines", "words"] : ["lines", "words", "chars"];

      const split = SplitText.create(heading, {
        type: typesToSplit.join(","),
        mask: "lines",
        autoSplit: true,
        linesClass: "line",
        wordsClass: "word",
        charsClass: "letter",
        onSplit(instance) {
          const targets = instance[type];
          const config = splitConfig[type];

          if (!targets || !targets.length) return;

          const animation = {
            yPercent: 110,
            duration: config.duration,
            stagger: config.stagger,
            ease: "expo.out"
          };

          if (isImmediate) {
            return gsap.from(targets, {
              ...animation,
              delay: 0.2
            });
          }

          const tween = gsap.from(targets, {
            ...animation,
            scrollTrigger: {
              trigger: heading,
              start: "top 80%",
              once: true
            }
          });

          if (tween.scrollTrigger) triggers.push(tween.scrollTrigger);
          return tween;
        }
      });

      splits.push(split);
    });

    registerDestroyer(() => {
      triggers.forEach((t) => {
        try {
          t.kill();
        } catch (e) {}
      });

      splits.forEach((s) => {
        try {
          if (Array.isArray(s)) s.forEach((x) => x && x.revert && x.revert());
          else if (s && s.revert) s.revert();
        } catch (e) {}
      });
    });
  }

  function initOverlapFade() {
    if (typeof gsap === "undefined" || typeof ScrollTrigger === "undefined") return;

    gsap.registerPlugin(ScrollTrigger);

    const triggers = [];
    const heroVisual = document.querySelector(".hero_canvas");

    document.querySelectorAll('.section_text_loop[data-overlap="true"]').forEach((section) => {
      const inner = section.querySelector(".section_text_inner") || section;

      gsap.set(inner, { y: "25vh" });

      const tl = gsap.timeline({
        scrollTrigger: {
          trigger: section,
          start: "top bottom",
          end: "top top",
          scrub: true,
          invalidateOnRefresh: true,
          onUpdate: (self) => {
            if (!heroVisual) return;
            if (isHeroListMode) return;

            gsap.set(heroVisual, { opacity: 1 - self.progress });
          }
        }
      });

      if (tl.scrollTrigger) triggers.push(tl.scrollTrigger);

      tl.to(inner, { y: 0, ease: "none" }, 0);
    });

    registerDestroyer(() => {
      triggers.forEach((t) => {
        try {
          t.kill();
        } catch (e) {}
      });
    });
  }

  function initModeSwitcherPill() {
    if (typeof gsap === "undefined") return;

    const switcherInner = document.querySelector(".mode_switcher_inner");
    if (!switcherInner) return;

    const items = Array.from(switcherInner.querySelectorAll(".mode_switcher_left, .mode_switcher_right"));
    if (items.length < 2) return;

    if (!items.some((item) => item.classList.contains("is--active"))) {
      items[0].classList.add("is--active");
    }

    let pill = switcherInner.querySelector(".mode_switcher_pill");

    if (!pill) {
      pill = document.createElement("div");
      pill.className = "mode_switcher_pill";
      pill.style.opacity = "0";
      pill.style.visibility = "hidden";
      switcherInner.insertBefore(pill, switcherInner.firstChild);
    }

    let pillVisible = false;

    switcherInner.style.position = "relative";
    switcherInner.style.overflow = "hidden";

    gsap.set(pill, {
      position: "absolute",
      left: 0,
      top: 0,
      zIndex: 0,
      pointerEvents: "none",
      borderRadius: "999em",
      autoAlpha: 0
    });

    items.forEach((item) => {
      item.style.position = "relative";
      item.style.zIndex = "1";
    });

    function getActiveItem() {
      return switcherInner.querySelector(".mode_switcher_left.is--active, .mode_switcher_right.is--active") || items[0];
    }

    function revealPill() {
      pillVisible = true;

      gsap.to(pill, {
        autoAlpha: 1,
        duration: 0.35,
        ease: "power2.out",
        overwrite: "auto"
      });
    }

    function hidePill() {
      pillVisible = false;
      gsap.set(pill, { autoAlpha: 0 });
    }

    function movePill(animate = true) {
      const activeItem = getActiveItem();
      const innerRect = switcherInner.getBoundingClientRect();
      const activeRect = activeItem.getBoundingClientRect();

      const vars = {
        x: activeRect.left - innerRect.left,
        y: activeRect.top - innerRect.top,
        width: activeRect.width,
        height: activeRect.height,
        duration: animate ? 0.55 : 0,
        ease: "expo.out",
        overwrite: true
      };

      gsap.to(pill, vars);
    }

    items.forEach((item) => {
      item.addEventListener("click", () => {
        requestAnimationFrame(() => {
          movePill(true);
          if (pillVisible) revealPill();
        });
      });
    });

    const observer = new MutationObserver(() => {
      movePill(true);
    });

    items.forEach((item) => {
      observer.observe(item, {
        attributes: true,
        attributeFilter: ["class"]
      });
    });

    const resizeObserver = new ResizeObserver(() => movePill(false));
    resizeObserver.observe(switcherInner);
    items.forEach((item) => resizeObserver.observe(item));

    gsap.delayedCall(0.3, () => {
      requestAnimationFrame(() => {
        movePill(false);
      });
    });
    window.VDJ_refreshModeSwitcherPill = function (delay = 0, animate = false) {
      hidePill();

      gsap.delayedCall(delay, () => {
        movePill(animate);
        requestAnimationFrame(() => {
          movePill(animate);
          revealPill();
        });
      });
    };

    registerDestroyer(() => {
      observer.disconnect();
      resizeObserver.disconnect();
      delete window.VDJ_refreshModeSwitcherPill;
    });
  }

  function initCanvas() {
  if (typeof gsap === "undefined" || typeof InertiaPlugin === "undefined") return;

  gsap.registerPlugin(InertiaPlugin);

  const viewport = document.querySelector(".canvas_viewport");
  const stage = document.querySelector(".canvas_stage");
  const source = document.querySelector(".project_cards_source");
  const dragButton = document.getElementById("drag_active");
  const overlay = document.querySelector(".canvas_overlay_content");
  const disappearTriggers = document.querySelectorAll('[data-pressed="disappear"]');

  if (!viewport || !stage || !source) return;

  const sourceCards = Array.from(source.querySelectorAll(".project_card"));
  if (!sourceCards.length) return;

  const currentPath = window.location.pathname.replace(/\/+$/, "") || "/";
  const shouldStartInDragMode = currentPath === "/ons-werk";

  const CARD_RATIO = 26 / 20;

  const BREAKPOINTS = {
    mobile: 767,
    tablet: 991
  };

  const DRAG_THRESHOLD = 4;
  const CANVAS_IDLE_SCALE = 0.92;
  const CANVAS_ACTIVE_SCALE = 1;
  const FLOAT_DISTANCE = 6;
  const FLOAT_ROTATION = 0.5;

  const GYRO_MAX_TILT = 32;
  const GYRO_DURATION = 1.1;

  const state = {
    x: 0,
    y: 0,
    scale: CANVAS_IDLE_SCALE,
    isDragging: false,
    hasMoved: false,
    startX: 0,
    startY: 0
  };

  const bounds = {
    minX: 0,
    maxX: 0,
    minY: 0,
    maxY: 0
  };

  let isDragEnabled = false;
  let inertiaTween = null;
  let cardWidth = 0;
  let cardHeight = 0;
  let gap = 0;
  let padding = 0;
  let cols = 0;
  let rows = 0;
  let gridWidth = 0;
  let gridHeight = 0;
  let contentWidth = 0;
  let contentHeight = 0;
  let rafQueued = false;
  let idleTickerAdded = false;
  let floatingTweens = [];
  let resizeTimer = null;
  let destroyed = false;

  let gyroEnabled = false;
  let gyroTween = null;

  function isMobile() {
    return window.matchMedia(`(max-width: ${BREAKPOINTS.mobile}px)`).matches;
  }

  function isMobileGyroDevice() {
    return isMobile() && "DeviceOrientationEvent" in window;
  }

  function clampPosition() {
    state.x = gsap.utils.clamp(bounds.minX, bounds.maxX, state.x);
    state.y = gsap.utils.clamp(bounds.minY, bounds.maxY, state.y);
  }

  function bounceToBounds() {
    const clampedX = gsap.utils.clamp(bounds.minX, bounds.maxX, state.x);
    const clampedY = gsap.utils.clamp(bounds.minY, bounds.maxY, state.y);

    if (clampedX === state.x && clampedY === state.y) return;

    gsap.to(state, {
      x: clampedX,
      y: clampedY,
      duration: 0.7,
      ease: "elastic.out(1, 0.75)",
      overwrite: true,
      onUpdate: render
    });
  }

  function render() {
    stage.style.transformOrigin = "50% 50%";
    stage.style.transform = `translate3d(${state.x}px, ${state.y}px, 0) scale(${state.scale})`;
  }

  function computeBounds() {
    const vw = viewport.clientWidth;
    const vh = viewport.clientHeight;

    if (contentWidth <= vw) {
      bounds.minX = (vw - contentWidth) / 2;
      bounds.maxX = bounds.minX;
    } else {
      bounds.minX = vw - contentWidth;
      bounds.maxX = 0;
    }

    if (contentHeight <= vh) {
      bounds.minY = (vh - contentHeight) / 2;
      bounds.maxY = bounds.minY;
    } else {
      bounds.minY = vh - contentHeight;
      bounds.maxY = 0;
    }
  }

  function computeLayoutMetrics() {
    const rem = parseFloat(getComputedStyle(document.documentElement).fontSize) || 16;
    const vw = Math.max(viewport.clientWidth, 1);
    const vh = Math.max(viewport.clientHeight, 1);

    const mobile = vw <= BREAKPOINTS.mobile;
    const tablet = vw > BREAKPOINTS.mobile && vw <= BREAKPOINTS.tablet;

    const minCardWidthRem = mobile ? 9.5 : tablet ? 13 : 16;
    const maxCardWidthRem = mobile ? 14 : tablet ? 18 : 22;
    
    const gapRem = mobile ? 1 : tablet ? 2 : 4;
    const paddingRem = mobile ? 1.5 : tablet ? 2 : 4;
    
    const worldMinScaleX = mobile ? 1.8 : tablet ? 1.15 : 1.35;
    const worldMinScaleY = mobile ? 1.9 : tablet ? 1.15 : 1.35;

    const minCardWidth = minCardWidthRem * rem;
    const maxCardWidth = maxCardWidthRem * rem;
    const baseGap = gapRem * rem;
    const basePadding = paddingRem * rem;
    const availableWidth = Math.max(vw - basePadding * 2, minCardWidth);

    const maxColsByWidth = Math.max(
      1,
      Math.floor((availableWidth + baseGap) / (minCardWidth + baseGap))
    );

    if (mobile) {
      cols = Math.min(sourceCards.length, 3);
    } else if (tablet) {
      cols = Math.min(sourceCards.length, 3, maxColsByWidth);
    } else {
      cols = Math.min(sourceCards.length, maxColsByWidth);
    }

    rows = Math.ceil(sourceCards.length / cols);

    if (cols > 1) {
      cardWidth = Math.min(maxCardWidth, (availableWidth - baseGap * (cols - 1)) / cols);
    } else {
      cardWidth = Math.min(maxCardWidth, availableWidth);
    }

    cardHeight = cardWidth * CARD_RATIO;
    gap = baseGap;
    padding = basePadding;

    gridWidth = cols * cardWidth + Math.max(cols - 1, 0) * gap;
    gridHeight = rows * cardHeight + Math.max(rows - 1, 0) * gap;
    contentWidth = gridWidth + padding * 2;
    contentHeight = gridHeight + padding * 2;

    const targetContentWidth = vw * worldMinScaleX;
    const targetContentHeight = vh * worldMinScaleY;

    const scaleX = targetContentWidth / Math.max(contentWidth, 1);
    const scaleY = targetContentHeight / Math.max(contentHeight, 1);

    const worldScale = mobile
        ? Math.max(1.15, Math.min(1.9, Math.max(scaleX, scaleY)))
      : tablet
        ? Math.max(1, Math.min(1.18, Math.max(scaleX, scaleY)))
        : Math.max(1, scaleX, scaleY);

    cardWidth *= worldScale;
    cardHeight *= worldScale;
    gap *= worldScale;
    padding *= worldScale;

    gridWidth = cols * cardWidth + Math.max(cols - 1, 0) * gap;
    gridHeight = rows * cardHeight + Math.max(rows - 1, 0) * gap;
    contentWidth = gridWidth + padding * 2;
    contentHeight = gridHeight + padding * 2;

    computeBounds();
  }

  function centerView() {
    const vw = viewport.clientWidth;
    const vh = viewport.clientHeight;

    state.x = (vw - contentWidth) / 2;
    state.y = (vh - contentHeight) / 2;

    render();
  }

  function setLinksEnabled(enabled) {
    const links = stage.querySelectorAll(".project_card_link");

    links.forEach((link) => {
      if (enabled) {
        link.style.pointerEvents = "auto";
        link.removeAttribute("tabindex");
        link.setAttribute("aria-disabled", "false");
      } else {
        link.style.pointerEvents = "none";
        link.setAttribute("tabindex", "-1");
        link.setAttribute("aria-disabled", "true");
      }
    });
  }

  function buildWorld() {
    stage.innerHTML = "";
    stage.style.position = "absolute";
    stage.style.width = `${contentWidth}px`;
    stage.style.height = `${contentHeight}px`;
    stage.style.left = "0px";
    stage.style.top = "0px";

    sourceCards.forEach((sourceCard, index) => {
      const card = sourceCard.cloneNode(true);
      delete card.dataset.hoverInitialized;

      const row = Math.floor(index / cols);
      const col = index % cols;
      const isLastRow = row === rows - 1;
      const itemsInRow = isLastRow ? sourceCards.length - row * cols : cols;
      const rowWidth = itemsInRow * cardWidth + Math.max(itemsInRow - 1, 0) * gap;
      const rowOffsetX = (gridWidth - rowWidth) / 2;
      const x = padding + rowOffsetX + col * (cardWidth + gap);
      const y = padding + row * (cardHeight + gap);

      card.style.position = "absolute";
      card.style.left = `${x}px`;
      card.style.top = `${y}px`;
      card.style.width = `${cardWidth}px`;
      card.style.height = `${cardHeight}px`;

      const cardLinks = card.querySelectorAll(".project_card_link");

      cardLinks.forEach((link) => {
        link.addEventListener("click", (e) => {
          if (!isDragEnabled || state.hasMoved || state.isDragging) {
            e.preventDefault();
            e.stopPropagation();
          }
        });
      });

      card.addEventListener("click", (e) => {
        if (state.hasMoved) e.preventDefault();
      });

      stage.appendChild(card);
    });

    setLinksEnabled(isDragEnabled);
    initProjectCardHover(stage);
  }

  function syncSceneRaf() {
    if (rafQueued) return;

    rafQueued = true;

    requestAnimationFrame(() => {
      rafQueued = false;
      render();
    });
  }

  function killInertia() {
    if (inertiaTween) {
      inertiaTween.kill();
      inertiaTween = null;
    }
  }

  function killGyroTween() {
    if (gyroTween) {
      gyroTween.kill();
      gyroTween = null;
    }
  }

  function startInertia() {
    const vx = InertiaPlugin.getVelocity(state, "x");
    const vy = InertiaPlugin.getVelocity(state, "y");

    inertiaTween = gsap.to(state, {
      inertia: {
        x: {
          velocity: vx,
          resistance: 1000,
          min: bounds.minX,
          max: bounds.maxX
        },
        y: {
          velocity: vy,
          resistance: 1000,
          min: bounds.minY,
          max: bounds.maxY
        }
      },
      duration: 2.5,
      ease: "power3.out",
      onUpdate: render,
      onComplete: () => {
        inertiaTween = null;
        bounceToBounds();
        refreshIdleAnimation();
      }
    });
  }

  function setScrollEnabled(enabled) {
    if (enabled) {
      document.documentElement.style.overflow = "";
      document.body.style.overflow = "";
      document.body.style.touchAction = "";

      if (window.lenis && typeof window.lenis.start === "function") window.lenis.start();
    } else {
      document.documentElement.style.overflow = "hidden";
      document.body.style.overflow = "hidden";
      document.body.style.touchAction = "none";

      if (window.lenis && typeof window.lenis.stop === "function") window.lenis.stop();
    }
  }

  function isOverlayVisible() {
    if (!overlay) return false;
    if (overlay.style.display === "none") return false;
    return getComputedStyle(overlay).display !== "none";
  }

  function shouldRunIdle() {
    return isOverlayVisible() && !isDragEnabled && !state.isDragging && !inertiaTween;
  }

  function startIdleAnimation() {
    if (idleTickerAdded) return;

    const cards = Array.from(stage.querySelectorAll(".project_card"));

    floatingTweens = cards.map((card, index) => {
      const directionX = index % 2 === 0 ? 1 : -1;
      const directionY = index % 3 === 0 ? -1 : 1;
      const distanceX = FLOAT_DISTANCE * (0.45 + (index % 5) * 0.14) * directionX;
      const distanceY = FLOAT_DISTANCE * (0.55 + (index % 4) * 0.12) * directionY;
      const rotation = FLOAT_ROTATION * (index % 2 === 0 ? 1 : -1);
      const duration = 3.4 + (index % 6) * 0.35;

      return gsap.to(card, {
        x: distanceX,
        y: distanceY,
        rotation: rotation,
        duration: duration,
        ease: "sine.inOut",
        repeat: -1,
        yoyo: true,
        delay: index * 0.04
      });
    });

    idleTickerAdded = true;
  }

  function stopIdleAnimation() {
    if (!idleTickerAdded) return;

    floatingTweens.forEach((tween) => tween.kill());
    floatingTweens = [];

    gsap.to(stage.querySelectorAll(".project_card"), {
      x: 0,
      y: 0,
      rotation: 0,
      duration: 0.45,
      ease: "power3.out",
      overwrite: true
    });

    idleTickerAdded = false;
  }

  function refreshIdleAnimation() {
    if (shouldRunIdle()) startIdleAnimation();
    else stopIdleAnimation();
  }

  function onDeviceOrientation(e) {
    if (!isDragEnabled || !gyroEnabled || state.isDragging || !isMobile()) return;
    if (state.hasMoved) return;
    if (!Number.isFinite(e.beta) && !Number.isFinite(e.gamma)) return;

    const beta = gsap.utils.clamp(-GYRO_MAX_TILT, GYRO_MAX_TILT, e.beta || 0);
    const gamma = gsap.utils.clamp(-GYRO_MAX_TILT, GYRO_MAX_TILT, e.gamma || 0);

    const targetX = gsap.utils.mapRange(
      -GYRO_MAX_TILT,
      GYRO_MAX_TILT,
      bounds.maxX,
      bounds.minX,
      gamma
    );

    const targetY = gsap.utils.mapRange(
      -GYRO_MAX_TILT,
      GYRO_MAX_TILT,
      bounds.maxY,
      bounds.minY,
      beta
    );

    killInertia();

    gyroTween = gsap.to(state, {
      x: targetX,
      y: targetY,
      duration: GYRO_DURATION,
      ease: "power3.out",
      overwrite: "auto",
      onUpdate: render
    });
  }

  function enableGyroCanvas() {
    if (!isMobileGyroDevice() || gyroEnabled) return;

    if (
      typeof DeviceOrientationEvent !== "undefined" &&
      typeof DeviceOrientationEvent.requestPermission === "function"
    ) {
      DeviceOrientationEvent.requestPermission()
        .then((response) => {
          if (response !== "granted" || destroyed) return;

          gyroEnabled = true;
          window.addEventListener("deviceorientation", onDeviceOrientation, true);
        })
        .catch(() => {});
    } else {
      gyroEnabled = true;
      window.addEventListener("deviceorientation", onDeviceOrientation, true);
    }
  }

  function disableGyroCanvas() {
    if (!gyroEnabled) return;

    gyroEnabled = false;
    killGyroTween();
    window.removeEventListener("deviceorientation", onDeviceOrientation, true);
  }

  function setDragEnabled(enabled) {
    isDragEnabled = enabled;

    if (dragButton) dragButton.classList.toggle("is-active", isDragEnabled);

    viewport.style.cursor = isDragEnabled ? "grab" : "default";
    setScrollEnabled(!isDragEnabled);
    setLinksEnabled(isDragEnabled);

    gsap.to(state, {
      scale: isDragEnabled ? CANVAS_ACTIVE_SCALE : CANVAS_IDLE_SCALE,
      duration: isDragEnabled ? 0.9 : 0.55,
      ease: isDragEnabled ? "expo.out" : "power3.out",
      overwrite: true,
      onUpdate: render
    });

    if (!isDragEnabled) {
      killInertia();
      killGyroTween();
      state.isDragging = false;
      state.hasMoved = false;
      disableGyroCanvas();
    } else {
      state.hasMoved = false;
      enableGyroCanvas();
    }

    refreshIdleAnimation();
  }

  function showCanvasControlsImmediately() {
    const switcher = document.querySelector(".canvas_mode_switcher_wrapper");
    const worldOverlay = document.querySelector(".canvas_world_overlay");

    if (switcher) {
      gsap.set(switcher, {
        opacity: 1,
        y: 0,
        pointerEvents: "auto"
      });
    }

    if (worldOverlay) {
      gsap.set(worldOverlay, {
        opacity: 1,
        y: 0,
        filter: "blur(0px)",
        pointerEvents: "auto"
      });
    }

    if (window.VDJ_refreshModeSwitcherPill) {
      window.VDJ_refreshModeSwitcherPill(0.05, false);
    }
  }

  function hideOverlayImmediately() {
    if (!overlay) return;

    overlay.style.transition = "";
    overlay.style.opacity = "0";
    overlay.style.display = "none";
    overlay.style.pointerEvents = "none";
  }

  function showOpeningState() {
    const switcher = document.querySelector(".canvas_mode_switcher_wrapper");
    const worldOverlay = document.querySelector(".canvas_world_overlay");
    const overlayInner = overlay ? overlay.querySelector(".canvas_overlay_inner") : null;
    const overlayTextWrapper = overlay ? overlay.querySelector(".overlay_text_wrapper") : null;
    const buttonWrapper = overlay ? overlay.querySelector(".button_wrapper") : null;
    const overlayTexts = overlayTextWrapper
      ? Array.from(overlayTextWrapper.children).filter(
          (child) => child !== buttonWrapper && !child.contains(buttonWrapper)
        )
      : [];
    const overlayBlur = overlay ? overlay.querySelector(".canvas_overlay_bg_blur") : null;

    if (switcher) {
      gsap.to(switcher, {
        opacity: 0,
        y: 20,
        duration: 0.35,
        pointerEvents: "none",
        ease: "power3.out"
      });
    }

    if (worldOverlay) {
      gsap.to(worldOverlay, {
        opacity: 0,
        y: 16,
        filter: "blur(8px)",
        duration: 0.35,
        pointerEvents: "none",
        ease: "power3.out"
      });
    }

    if (!overlay) return;

    overlay.style.display = "";
    overlay.style.pointerEvents = "auto";

    gsap.set(overlay, { opacity: 0 });

    if (overlayInner) {
      gsap.set(overlayInner, {
        opacity: 0,
        y: -18,
        filter: "blur(10px)"
      });
    }

    if (overlayBlur) {
      gsap.set(overlayBlur, {
        opacity: 0,
        filter: "blur(18px)"
      });
    }

    if (overlayTexts.length) {
      gsap.set(overlayTexts, {
        opacity: 0,
        y: 18
      });
    }

    if (buttonWrapper) {
      gsap.set(buttonWrapper, {
        opacity: 0,
        y: 14
      });
    }

    const tl = gsap.timeline({
      defaults: {
        ease: "power3.out"
      },
      onComplete: refreshIdleAnimation
    });

    tl.to(overlay, { opacity: 1, duration: 0.45 }, 0);

    if (overlayBlur) {
      tl.to(
        overlayBlur,
        {
          opacity: 1,
          filter: "blur(0px)",
          duration: 0.55
        },
        0.05
      );
    }

    if (overlayInner) {
      tl.to(
        overlayInner,
        {
          opacity: 1,
          y: 0,
          filter: "blur(0px)",
          duration: 0.6
        },
        0.08
      );
    }

    if (overlayTexts.length) {
      tl.to(
        overlayTexts,
        {
          opacity: 1,
          y: 0,
          duration: 0.55,
          stagger: 0.055
        },
        0.16
      );
    }

    if (buttonWrapper) {
      tl.to(
        buttonWrapper,
        {
          opacity: 1,
          y: 0,
          duration: 0.16,
          ease: "power2.out"
        },
        0.12
      );
    }
  }

  function resetToOpeningState() {
    killInertia();
    killGyroTween();
    stopIdleAnimation();
    disableGyroCanvas();

    if (window.VDJ_resetHeroListMode) {
      window.VDJ_resetHeroListMode();
    }

    setDragEnabled(false);
    centerView();
    showOpeningState();
  }

  function rebuildScene(preservePosition) {
    const prevX = state.x;
    const prevY = state.y;

    killInertia();
    killGyroTween();
    computeLayoutMetrics();
    buildWorld();

    if (preservePosition) {
      state.x = prevX;
      state.y = prevY;
      clampPosition();
      render();
    } else {
      centerView();
    }

    viewport.style.cursor = isDragEnabled ? "grab" : "default";
    refreshIdleAnimation();
  }

  function onDragButtonClick() {
    setDragEnabled(!isDragEnabled);
  }

  function onWheel(e) {
    if (isDragEnabled) e.preventDefault();
  }

  function onPointerDown(e) {
    if (!isDragEnabled) return;

    stopIdleAnimation();
    killInertia();
    killGyroTween();

    state.isDragging = true;
    state.hasMoved = false;
    state.startX = e.clientX - state.x;
    state.startY = e.clientY - state.y;
    viewport.style.cursor = "grabbing";

    if (viewport.setPointerCapture && e.pointerId !== undefined) {
      try {
        viewport.setPointerCapture(e.pointerId);
      } catch (err) {}
    }
  }

  function onPointerMove(e) {
    if (!state.isDragging || !isDragEnabled) return;

    const overscroll = 0.18;

    let newX = e.clientX - state.startX;
    let newY = e.clientY - state.startY;

    if (newX > bounds.maxX) newX = bounds.maxX + (newX - bounds.maxX) * overscroll;
    if (newX < bounds.minX) newX = bounds.minX + (newX - bounds.minX) * overscroll;
    if (newY > bounds.maxY) newY = bounds.maxY + (newY - bounds.maxY) * overscroll;
    if (newY < bounds.minY) newY = bounds.minY + (newY - bounds.minY) * overscroll;

    const vx = newX - state.x;
    const vy = newY - state.y;

    if (Math.abs(vx) > DRAG_THRESHOLD || Math.abs(vy) > DRAG_THRESHOLD) {
      state.hasMoved = true;
    }

    state.x = newX;
    state.y = newY;

    syncSceneRaf();
  }

  function onPointerUp(e) {
    if (!state.isDragging) return;

    state.isDragging = false;
    viewport.style.cursor = isDragEnabled ? "grab" : "default";

    if (viewport.releasePointerCapture && e && e.pointerId !== undefined) {
      try {
        viewport.releasePointerCapture(e.pointerId);
      } catch (err) {}
    }

    if (state.hasMoved && isDragEnabled) {
      startInertia();
      bounceToBounds();
    } else {
      bounceToBounds();
      refreshIdleAnimation();
    }
  }

  function onResize() {
    clearTimeout(resizeTimer);

    resizeTimer = setTimeout(() => {
      if (destroyed) return;

      killInertia();
      killGyroTween();
      stopIdleAnimation();
      rebuildScene(false);
      render();
      refreshIdleAnimation();

      if (isDragEnabled) {
        state.hasMoved = false;

        if (isMobileGyroDevice()) enableGyroCanvas();
        else disableGyroCanvas();
      }

      if (window.VDJ_refreshModeSwitcherPill) {
        window.VDJ_refreshModeSwitcherPill(0, false);
      }

      safeRefreshScrollTrigger();
    }, 120);
  }

  const disappearHandlers = [];
  const resetButtons = document.querySelectorAll("[data-canvas-reset]");
  const resetHandlers = [];

  function wireDisappearTriggers() {
    if (!disappearTriggers.length || !overlay) return;

    const overlayInner = overlay.querySelector(".canvas_overlay_inner");
    const overlayTextWrapper = overlay.querySelector(".overlay_text_wrapper");
    const overlayHeading = overlayTextWrapper ? overlayTextWrapper.querySelector("h1") : null;
    const buttonWrapper = overlay.querySelector(".button_wrapper");
    const overlayBlur = overlay.querySelector(".canvas_overlay_bg_blur");

    const switcher = document.querySelector(".canvas_mode_switcher_wrapper");
    const worldOverlay = document.querySelector(".canvas_world_overlay");

    const worldOverlayInner = worldOverlay ? worldOverlay.querySelector(".canvas_overlay_inner") : null;
    const worldOverlayTexts = worldOverlay ? worldOverlay.querySelectorAll(".overlay_text_wrapper > *") : [];

    const switcherInner = switcher ? switcher.querySelector(".mode_switcher_inner") : null;
    const switcherLeft = switcher ? switcher.querySelector(".mode_switcher_left") : null;
    const switcherRight = switcher ? switcher.querySelector(".mode_switcher_right") : null;
    const switcherTexts = switcher ? switcher.querySelectorAll(".text_eye") : [];

    const leftIcon = switcherLeft ? switcherLeft.querySelector(".eye_icon") : null;
    const rightIcon = switcherRight ? switcherRight.querySelector(".eye_icon") : null;

    const leftPaths = leftIcon ? leftIcon.querySelectorAll("path") : [];
    const rightPaths = rightIcon ? rightIcon.querySelectorAll("path") : [];

    let transitionTween = null;

    function prepIconPaths(paths) {
      paths.forEach((path) => {
        try {
          const length = path.getTotalLength();
          const paddedLength = length + 4;

          path.style.strokeDasharray = paddedLength;
          path.style.strokeDashoffset = paddedLength;
          path.style.opacity = "1";
          path.style.strokeLinecap = "round";
          path.style.strokeLinejoin = "round";
        } catch (e) {}
      });
    }

    if (switcher) {
      gsap.set(switcher, {
        opacity: 0,
        y: 20,
        pointerEvents: "none"
      });
    }

    const switcherPill = switcher ? switcher.querySelector(".mode_switcher_pill") : null;
    if (switcherPill) {
      gsap.set(switcherPill, { autoAlpha: 0 });
    }

    if (worldOverlay) {
      gsap.set(worldOverlay, {
        opacity: 0,
        y: 16,
        filter: "blur(8px)",
        pointerEvents: "none"
      });
    }

    if (worldOverlayTexts.length) {
      gsap.set(worldOverlayTexts, {
        opacity: 0,
        y: 12,
        filter: "blur(10px)"
      });
    }

    if (switcherInner) gsap.set(switcherInner, { opacity: 1 });

    if (switcherLeft) {
      gsap.set(switcherLeft, {
        opacity: 0,
        x: -14
      });
    }

    if (switcherRight) {
      gsap.set(switcherRight, {
        opacity: 0,
        x: 14
      });
    }

    if (switcherTexts.length) {
      gsap.set(switcherTexts, {
        opacity: 0,
        y: 8
      });
    }

    if (leftIcon) {
      gsap.set(leftIcon, {
        opacity: 1,
        scale: 1,
        transformOrigin: "50% 50%"
      });

      prepIconPaths(leftPaths);
    }

    if (rightIcon) {
      gsap.set(rightIcon, {
        opacity: 1,
        scale: 1,
        transformOrigin: "50% 50%"
      });

      prepIconPaths(rightPaths);
    }

    disappearTriggers.forEach((el) => {
      const handler = () => {
        if (transitionTween) transitionTween.kill();

        const switcherPill = switcher ? switcher.querySelector(".mode_switcher_pill") : null;
        if (switcherPill) {
          gsap.set(switcherPill, { autoAlpha: 0 });
        }

        stopIdleAnimation();

        overlay.style.pointerEvents = "none";
        overlay.style.willChange = "opacity";

        if (overlayInner) overlayInner.style.willChange = "transform, opacity, filter";
        if (overlayBlur) overlayBlur.style.willChange = "opacity, filter";
        if (worldOverlay) worldOverlay.style.willChange = "transform, opacity, filter";
        if (worldOverlayInner) worldOverlayInner.style.willChange = "transform, opacity, filter";

        let headingSplit = null;
        let headingTargets = null;

        if (overlayHeading && typeof SplitText !== "undefined" && typeof gsap !== "undefined") {
          headingSplit = SplitText.create(overlayHeading, {
            type: "lines,words",
            mask: "lines",
            autoSplit: false,
            linesClass: "line",
            wordsClass: "word"
          });

          headingTargets = headingSplit.words && headingSplit.words.length ? headingSplit.words : headingSplit.lines;
        }

        prepIconPaths(leftPaths);
        prepIconPaths(rightPaths);

        transitionTween = gsap.timeline({
          defaults: {
            ease: "power3.out"
          },
          onComplete: () => {
            overlay.style.display = "none";
            overlay.style.opacity = "0";
            overlay.style.pointerEvents = "none";
            overlay.style.willChange = "";

            if (overlayInner) overlayInner.style.willChange = "";
            if (overlayBlur) overlayBlur.style.willChange = "";
            if (worldOverlay) worldOverlay.style.willChange = "";
            if (worldOverlayInner) worldOverlayInner.style.willChange = "";

            if (headingSplit && headingSplit.revert) {
              try {
                headingSplit.revert();
              } catch (e) {}
            }

            transitionTween = null;
            refreshIdleAnimation();
          }
        });

        if (headingTargets && headingTargets.length) {
          transitionTween.to(
            headingTargets,
            {
              yPercent: -110,
              opacity: 0,
              duration: 0.75,
              stagger: 0.035,
              ease: "expo.inOut"
            },
            0
          );
        } else if (overlayHeading) {
          transitionTween.to(
            overlayHeading,
            {
              y: -18,
              opacity: 0,
              duration: 0.6,
              ease: "expo.inOut"
            },
            0
          );
        }

        if (buttonWrapper) {
          transitionTween.to(
            buttonWrapper,
            {
              y: 14,
              opacity: 0,
              duration: 0.35,
              ease: "power2.out"
            },
            0.28
          );
        }

        if (overlayBlur) {
          transitionTween.to(
            overlayBlur,
            {
              opacity: 0,
              filter: "blur(18px)",
              duration: 0.55,
              ease: "power2.out"
            },
            0.58
          );
        }

        if (overlayInner) {
          transitionTween.to(
            overlayInner,
            {
              y: -18,
              opacity: 0,
              filter: "blur(10px)",
              duration: 0.55,
              ease: "power2.out"
            },
            0.62
          );
        }

        transitionTween.to(
          overlay,
          {
            opacity: 0,
            duration: 0.42,
            ease: "power2.out"
          },
          0.68
        );

        if (switcher) {
          transitionTween.to(
            switcher,
            {
              opacity: 1,
              y: 0,
              duration: 0.5,
              pointerEvents: "auto",
              ease: "power3.out"
            },
            0.78
          );
        }

        if (worldOverlay) {
          transitionTween.to(
            worldOverlay,
            {
              opacity: 1,
              y: 0,
              filter: "blur(0px)",
              duration: 0.55,
              pointerEvents: "auto",
              ease: "power3.out"
            },
            0.84
          );
        }

        if (worldOverlayTexts.length) {
          transitionTween.to(
            worldOverlayTexts,
            {
              opacity: 1,
              y: 0,
              filter: "blur(0px)",
              duration: 0.55,
              stagger: 0.08,
              ease: "power2.out"
            },
            0.96
          );
        }

        if (switcherLeft) {
          transitionTween.to(
            switcherLeft,
            {
              opacity: 1,
              x: 0,
              duration: 0.42
            },
            0.9
          );
        }

        if (switcherRight) {
          transitionTween.to(
            switcherRight,
            {
              opacity: 1,
              x: 0,
              duration: 0.42
            },
            0.96
          );
        }

        if (leftPaths.length) {
          transitionTween.to(
            leftPaths,
            {
              strokeDashoffset: 0,
              duration: 0.34,
              stagger: 0.06,
              ease: "power2.out"
            },
            0.98
          );
        }

        if (rightPaths.length) {
          transitionTween.to(
            rightPaths,
            {
              strokeDashoffset: 0,
              duration: 0.32,
              stagger: 0.055,
              ease: "power2.out"
            },
            1.04
          );
        }

        if (switcherTexts.length) {
          transitionTween.to(
            switcherTexts,
            {
              opacity: 1,
              y: 0,
              duration: 0.34,
              stagger: 0.08,
              ease: "power2.out"
            },
            1.08
          );
        }

        transitionTween.call(
          () => {
            if (window.VDJ_refreshModeSwitcherPill) {
              window.VDJ_refreshModeSwitcherPill(0.3, false);
            }
          },
          null,
          1.12
        );
      };

      el.addEventListener("click", handler);
      disappearHandlers.push({ el, handler });
    });
  }

  function buildWhenReady(attempt) {
    if (destroyed) return;

    const vw = viewport.clientWidth;
    const vh = viewport.clientHeight;

    if ((!vw || !vh) && attempt < 40) {
      requestAnimationFrame(() => buildWhenReady(attempt + 1));
      return;
    }

    rebuildScene(false);

    if (shouldStartInDragMode) {
      setDragEnabled(true);
      hideOverlayImmediately();
      showCanvasControlsImmediately();

      afterNextPaint(() => {
        if (destroyed) return;

        rebuildScene(true);
        showCanvasControlsImmediately();

        setTimeout(() => {
          if (destroyed) return;

          rebuildScene(true);
          showCanvasControlsImmediately();
          safeRefreshScrollTrigger();
        }, 80);
      });
    } else {
      setDragEnabled(false);
    }

    refreshIdleAnimation();
  }

  window.VDJ_canvas = {
    setDragEnabled,
    hideOverlayImmediately,
    resetToOpeningState,
    rebuild: rebuildScene
  };

  InertiaPlugin.track(state, "x,y");

  if (dragButton) dragButton.addEventListener("click", onDragButtonClick);

  window.addEventListener("wheel", onWheel, { passive: false });
  viewport.addEventListener("pointerdown", onPointerDown);
  window.addEventListener("pointermove", onPointerMove);
  window.addEventListener("pointerup", onPointerUp);
  window.addEventListener("pointercancel", onPointerUp);
  window.addEventListener("resize", onResize);

  resetButtons.forEach((button) => {
    const handler = () => resetToOpeningState();

    button.addEventListener("click", handler);
    resetHandlers.push({ button, handler });
  });

  wireDisappearTriggers();
  buildWhenReady(0);

  window.resetCanvas = function () {
    resetToOpeningState();
  };

  registerDestroyer(() => {
    destroyed = true;

    killInertia();
    killGyroTween();
    stopIdleAnimation();
    disableGyroCanvas();
    clearTimeout(resizeTimer);

    if (dragButton) dragButton.removeEventListener("click", onDragButtonClick);

    window.removeEventListener("wheel", onWheel, { passive: false });
    viewport.removeEventListener("pointerdown", onPointerDown);
    window.removeEventListener("pointermove", onPointerMove);
    window.removeEventListener("pointerup", onPointerUp);
    window.removeEventListener("pointercancel", onPointerUp);
    window.removeEventListener("resize", onResize);

    disappearHandlers.forEach(({ el, handler }) => {
      el.removeEventListener("click", handler);
    });

    resetHandlers.forEach(({ button, handler }) => {
      button.removeEventListener("click", handler);
    });

    try {
      InertiaPlugin.untrack(state);
    } catch (e) {}

    delete window.VDJ_canvas;
    delete window.resetCanvas;
  });
}

  function initHeroListToggle() {
    if (typeof gsap === "undefined") return;

    const heroList = document.querySelector(".hero_list");
    const heroCanvas = document.querySelector(".hero_canvas");
    const switcherRight = document.querySelector(".mode_switcher_right");
    const switcherLeft = document.querySelector(".mode_switcher_left");
    const textLoopSection = document.querySelector(".section_text_loop");

    if (!heroList || !switcherRight || !switcherLeft) return;

    const heroListItems = heroList.children ? Array.from(heroList.children) : [];
    let toggleTween = null;
    let isOpen = false;

    gsap.set(heroList, {
      opacity: 0,
      y: 24,
      filter: "blur(12px)",
      pointerEvents: "none"
    });

    if (heroListItems.length) {
      gsap.set(heroListItems, {
        opacity: 0,
        y: 16
      });
    }

    function openHeroList() {
      if (isOpen) return;
      isOpen = true;
      isHeroListMode = true;

      gsap.to(window, { scrollTo: 0, duration: 0.6, ease: "power3.out" });

      if (window.VDJ_canvas && window.VDJ_canvas.setDragEnabled) {
        window.VDJ_canvas.setDragEnabled(false);
      }

      if (toggleTween) toggleTween.kill();

      switcherRight.classList.add("is--active");
      switcherLeft.classList.remove("is--active");

      if (textLoopSection) textLoopSection.style.display = "none";

      toggleTween = gsap.timeline({
        defaults: { ease: "power3.out" },
        onComplete: () => {
          afterNextPaint(() => {
            safeRefreshScrollTrigger();
          });
        }
      });

      if (heroCanvas) {
        toggleTween.to(
          heroCanvas,
          {
            opacity: 0,
            duration: 0.5,
            pointerEvents: "none"
          },
          0
        );
      }

      toggleTween.to(
        heroList,
        {
          opacity: 1,
          y: 0,
          filter: "blur(0px)",
          duration: 0.55,
          pointerEvents: "auto"
        },
        0
      );

      if (heroListItems.length) {
        toggleTween.to(
          heroListItems,
          {
            opacity: 1,
            y: 0,
            duration: 0.4,
            stagger: 0.06
          },
          0.12
        );
      }
    }

    function closeHeroList() {
      if (!isOpen) return;
      isOpen = false;
      isHeroListMode = false;

      gsap.to(window, { scrollTo: 0, duration: 0.6, ease: "power3.out" });

      if (window.VDJ_canvas && window.VDJ_canvas.setDragEnabled) {
        window.VDJ_canvas.setDragEnabled(true);
      }

      if (toggleTween) toggleTween.kill();

      switcherRight.classList.remove("is--active");
      switcherLeft.classList.add("is--active");

      if (textLoopSection) textLoopSection.style.display = "";

      toggleTween = gsap.timeline({
        defaults: { ease: "power3.out" },
        onComplete: () => {
          afterNextPaint(() => {
            safeRefreshScrollTrigger();
          });
        }
      });

      if (heroListItems.length) {
        toggleTween.to(
          heroListItems,
          {
            opacity: 0,
            y: 12,
            duration: 0.25,
            stagger: 0.04
          },
          0
        );
      }

      toggleTween.to(
        heroList,
        {
          opacity: 0,
          y: 20,
          filter: "blur(12px)",
          duration: 0.35,
          pointerEvents: "none"
        },
        0.1
      );

      if (heroCanvas) {
        toggleTween.to(
          heroCanvas,
          {
            opacity: 1,
            duration: 0.5,
            pointerEvents: "auto"
          },
          0.1
        );
      }
    }

    function resetHeroListMode() {
      if (toggleTween) toggleTween.kill();

      isOpen = false;
      isHeroListMode = false;

      switcherRight.classList.remove("is--active");
      switcherLeft.classList.add("is--active");

      if (textLoopSection) textLoopSection.style.display = "";

      gsap.set(heroList, {
        opacity: 0,
        y: 24,
        filter: "blur(12px)",
        pointerEvents: "none"
      });

      if (heroListItems.length) {
        gsap.set(heroListItems, {
          opacity: 0,
          y: 16
        });
      }

      if (heroCanvas) {
        gsap.set(heroCanvas, {
          opacity: 1,
          pointerEvents: "auto"
        });
      }

      if (window.VDJ_refreshModeSwitcherPill) {
        window.VDJ_refreshModeSwitcherPill(0, false);
      }
    }

    window.VDJ_resetHeroListMode = resetHeroListMode;

    switcherRight.addEventListener("click", openHeroList);
    switcherLeft.addEventListener("click", closeHeroList);

    registerDestroyer(() => {
      switcherRight.removeEventListener("click", openHeroList);
      switcherLeft.removeEventListener("click", closeHeroList);
      delete window.VDJ_resetHeroListMode;
    });
  }

  function initAll() {
    destroyAll();

    initLenis();
    initTextLoop();
    initFooterParallax();
    initMaskTextScrollReveal();
    initOverlapFade();
    initModeSwitcherPill();
    initCanvas();
    initHeroListToggle();

    if (typeof ScrollTrigger !== "undefined") {
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          ScrollTrigger.refresh();
        });
      });

      if (!loadRefreshBound && document.readyState !== "complete") {
        loadRefreshBound = true;
        window.addEventListener(
          "load",
          () => {
            ScrollTrigger.refresh();
          },
          { once: true }
        );
      }
    }
  }

  window.VDJ = {
    init: initAll,
    destroy: destroyAll
  };

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", initAll);
  } else {
    initAll();
  }
})();
